// Flax Typhoon SoftEther VPN bridge — masquerade + characteristic CLI flags
let _suspect_paths = dynamic([@"c:\windows\fonts\", @"c:\users\public\", @"c:\perflogs\", @"c:\programdata\", @"c:\windows\temp\", @"c:\windows\debug\"]);
let _softether_originals = dynamic(["vpnclient.exe","vpnbridge.exe","vpnserver.exe","vpncmd.exe","vpnclient_x64.exe","vpnbridge_x64.exe"]);
let _softether_cli_tokens = dynamic(["/server","/hub","/password:","AccountCreate","AccountConnect","RemoteEnable","BridgeCreate","HubCreate","NicCreate","vpncmd","/CMD","/CSV"]);
// Masquerade: PE original/internal filename betrays SoftEther even when on-disk name is conhost.exe etc.
let _renamed_softether =
    DeviceProcessEvents
    | where Timestamp > ago(7d)
    | where ProcessVersionInfoOriginalFileName in~ (_softether_originals)
         or ProcessVersionInfoInternalFileName in~ (_softether_originals)
         or ProcessVersionInfoCompanyName has "SoftEther"
         or ProcessVersionInfoProductName has "SoftEther" or ProcessVersionInfoProductName has "PacketiX"
    | where FileName !in~ (_softether_originals)        // file on disk has been renamed
         or tolower(FolderPath) has_any (_suspect_paths)
    | extend Signal = "SoftEther_Rename_Masquerade";
// Behavioural: any process invoking SoftEther's command vocabulary from a non-standard location
let _softether_cli =
    DeviceProcessEvents
    | where Timestamp > ago(7d)
    | where ProcessCommandLine has_any (_softether_cli_tokens)
    | where ProcessCommandLine has_any ("/server","AccountConnect","AccountCreate","vpncmd")
    | where tolower(FolderPath) has_any (_suspect_paths)
         or FileName in~ ("conhost.exe","dllhost.exe","lsass.exe","svchost.exe","taskhostw.exe","explorer.exe")
    | extend Signal = "SoftEther_CLI_Suspicious_Path";
union isfuzzy=true _renamed_softether, _softether_cli
| where InitiatingProcessAccountName !endswith "$"
| project Timestamp, DeviceName, Signal, AccountName, FileName, FolderPath,
          OriginalFileName = ProcessVersionInfoOriginalFileName,
          CompanyName = ProcessVersionInfoCompanyName,
          ProductName = ProcessVersionInfoProductName,
          ProcessCommandLine, SHA256,
          Parent = InitiatingProcessFileName, ParentCmd = InitiatingProcessCommandLine
| order by Timestamp desc
